from flask import Flask, render_template, render_template_string, request

app = Flask(__name__)

# BAD: render_template_string with user input (VULNERABLE!)
@app.route('/greet/bad')
def greet_bad():
    name = request.args.get('name', 'World')
    template = f'<h1>Hello {name}!</h1>'  # VULNERABLE!
    return render_template_string(template)

# GOOD: Use predefined template file
@app.route('/greet/safe')
def greet_safe():
    name = request.args.get('name', 'World')
    # templates/greet.html: <h1>Hello {{ name }}!</h1>
    return render_template('greet.html', name=name)  # SAFE

# GOOD: If you must use strings, escape user input
from markupsafe import escape

@app.route('/greet/escaped')
def greet_escaped():
    name = request.args.get('name', 'World')
    escaped_name = escape(name)  # Escape HTML/template syntax
    template = f'<h1>Hello {escaped_name}!</h1>'
    return render_template_string(template)  # SAFE (but not recommended)

from flask import Flask
from jinja2.sandbox import SandboxedEnvironment

app = Flask(__name__)

# Replace default environment with sandboxed version
class CustomSandboxedEnvironment(SandboxedEnvironment):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        # Whitelist allowed attributes
        self.allowed_filters = ['upper', 'lower', 'title']

    def is_safe_attribute(self, obj, attr, value):
        # Deny access to dangerous attributes
        if attr.startswith('_'):
            return False
        if attr in ['__init__', '__globals__', '__class__']:
            return False
        return True

app.jinja_env = CustomSandboxedEnvironment(
    autoescape=True,
    loader=app.jinja_loader
)

# Now template injection attempts will fail
@app.route('/sandboxed')
def sandboxed_route():
    user_input = request.args.get('input', '')
    # Even if attacker injects {{config}}, sandbox blocks it
    return render_template('page.html', data=user_input)
